const ICON_SUCCESS="check",STATE_COPIED="rd-is-copied",RESET_MS=1200;function getCopyText(e){if(e.dataset.copyText!=null)return e.dataset.copyText;if(e.dataset.copyTarget)return document.querySelector(e.dataset.copyTarget)?.textContent?.trim()||"";const t=e.closest("[data-copy]")||e.parentElement?.querySelector("[data-copy]");return t?t.getAttribute("href")||t.textContent.trim():""}function fallbackCopy(e){const t=document.createElement("textarea");t.value=e,t.style.position="fixed",t.style.opacity="0",t.style.pointerEvents="none",document.body.appendChild(t),t.select();const a=document.execCommand("copy");return t.remove(),a}document.addEventListener("click",async e=>{const t=e.target.closest(".rd-js-copy");if(!t||t.dataset.copyBusy)return;const a=getCopyText(t);if(!a)return;t.dataset.copyBusy="1";const o=()=>{t.dataset.icon=ICON_SUCCESS,t.classList.add(STATE_COPIED),clearTimeout(t._copyTimer),t._copyTimer=setTimeout(()=>{delete t.dataset.icon,t.classList.remove(STATE_COPIED),delete t.dataset.copyBusy},1200)};try{await navigator.clipboard.writeText(a),o()}catch{fallbackCopy(a)?o():delete t.dataset.copyBusy}});function labelCopyIcons(){document.querySelectorAll(".rd-js-copy").forEach(e=>{!e.getAttribute("aria-label")&&!e.getAttribute("title")&&!e.textContent.trim()&&e.setAttribute("aria-label","Copy")})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",labelCopyIcons):labelCopyIcons();
